import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.CMYkYJvz.js";const u=JSON.parse('{"title":"Remote Invoke v5 PoP Hardening","description":"Automatically synced English Remote Invoke v5 PoP Hardening documentation from docs-en/design/remote-invoke-v5-pop-hardening.md.","frontmatter":{"title":"Remote Invoke v5 PoP Hardening","description":"Automatically synced English Remote Invoke v5 PoP Hardening documentation from docs-en/design/remote-invoke-v5-pop-hardening.md.","editLink":false},"headers":[],"relativePath":"en/reference/design/remote-invoke-v5-pop-hardening.md","filePath":"en/reference/design/remote-invoke-v5-pop-hardening.md"}'),n={name:"en/reference/design/remote-invoke-v5-pop-hardening.md"};function i(l,e,s,d,c,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<blockquote><p>This page is automatically synced from <code>docs-en/design/remote-invoke-v5-pop-hardening.md</code>.</p></blockquote><h1 id="remote-invoke-v5-pop-hardening" tabindex="-1">Remote Invoke v5 PoP Hardening <a class="header-anchor" href="#remote-invoke-v5-pop-hardening" aria-label="Permalink to &quot;Remote Invoke v5 PoP Hardening&quot;">​</a></h1><blockquote><p>Status: implemented on the <code>feat/remote-invoke-v5-pop</code> branch. Scope: P0-1, P0-2, P0-3, P0-4, and their regression tests.</p></blockquote><p>This document records the English counterpart for the Remote Invoke v5 Proof-of-Possession hardening plan. The implementation moves caller-sensitive Remote Invoke operations away from caller-supplied identifiers and onto Ed25519 PoP-bound sessions.</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ol><li>Caller-sensitive relay operations must be bound to a caller Ed25519 public key fingerprint, not to self-reported caller identifiers alone.</li><li>SSH public-key authorization must not bypass v5 PoP. SSH approval creates a one-time claim that must be redeemed through the v5 claim flow.</li><li>Pairing and grant events must not leak reusable long-lived grant identifiers.</li><li>Multiple pairing watchers must be supported without exposing reusable grant credentials over SSE.</li></ol><h2 id="p0-1-ssh-route-ownership" tabindex="-1">P0-1: SSH Route Ownership <a class="header-anchor" href="#p0-1-ssh-route-ownership" aria-label="Permalink to &quot;P0-1: SSH Route Ownership&quot;">​</a></h2><p>SSH device-code routes are scoped to the registered client user. Route updates from a different user are rejected instead of replacing an existing device-code route. This prevents one account from hijacking another account&#39;s SSH pairing route.</p><p>Validation coverage:</p><ul><li>route registration carries the server-side user id;</li><li>heartbeat route refresh uses the persisted client record owner;</li><li>attempts to reuse a device code across users are rejected;</li><li>affected SSH grants are revoked when a route changes.</li></ul><h2 id="p0-2-ephemeral-transport-binding" tabindex="-1">P0-2: Ephemeral Transport Binding <a class="header-anchor" href="#p0-2-ephemeral-transport-binding" aria-label="Permalink to &quot;P0-2: Ephemeral Transport Binding&quot;">​</a></h2><p>Grant lookup freezes the caller ephemeral X25519 public key for the lifetime of the grant. A later lookup with a different caller ephemeral key is rejected.</p><p>This prevents a caller from rotating transport context under an existing grant and confusing encrypted open-call payload handling.</p><p>Validation coverage:</p><ul><li>first lookup may materialize the caller ephemeral key;</li><li>later lookups must use the same caller ephemeral key;</li><li>lookup returns the client ephemeral key required for open-call encryption;</li><li>nonce replay and canonical JSON checks remain enforced.</li></ul><h2 id="p0-3-grant-session-tokens" tabindex="-1">P0-3: Grant Session Tokens <a class="header-anchor" href="#p0-3-grant-session-tokens" aria-label="Permalink to &quot;P0-3: Grant Session Tokens&quot;">​</a></h2><p>Remote Invoke v5 uses short-lived <code>grant_session_token</code> bearer tokens for caller operations. Pairing and SSH approval paths issue one-time claim tokens; the caller redeems those claims with PoP and receives the short-lived session token.</p><p>Open-call requests must include:</p><ul><li><code>Authorization: Bearer &lt;grant_session_token&gt;</code>;</li><li>a PoP-signed canonical JSON request body;</li><li>encrypted command payloads bound to the saved transport context.</li></ul><p>Validation coverage:</p><ul><li>claim tokens are one-time-use;</li><li>session tokens are hashed at rest;</li><li>revoked, expired, or mismatched session tokens are rejected;</li><li>CLI callers refresh an expired or invalid session token through v5 lookup.</li></ul><h2 id="p0-4-sse-grant-leakage" tabindex="-1">P0-4: SSE Grant Leakage <a class="header-anchor" href="#p0-4-sse-grant-leakage" aria-label="Permalink to &quot;P0-4: SSE Grant Leakage&quot;">​</a></h2><p>SSE approval events no longer include reusable grant identifiers or transport keys. Pairing watchers receive only the data required to claim authorization. The caller must then complete the v5 claim flow with PoP.</p><p>Validation coverage:</p><ul><li>multiple watchers can observe the same pending pairing;</li><li>approval events omit long-lived grant ids and caller fingerprints;</li><li>watch tokens gate the pairing watch stream;</li><li>legacy v4 caller-sensitive endpoints return <code>410 protocol_version_not_supported</code>.</li></ul><h2 id="rollback-notes" tabindex="-1">Rollback Notes <a class="header-anchor" href="#rollback-notes" aria-label="Permalink to &quot;Rollback Notes&quot;">​</a></h2><p>This is an intentional v5 security break. A rollback must restore the previous Remote Invoke router and schema together; mixing v4 caller behavior with v5 token semantics is not supported.</p><p>Recommended rollback sequence:</p><ol><li>Stop the sync server.</li><li>Drop or restore the <code>bifrost_remote_invoke_*</code> tables to the previous schema.</li><li>Restore the previous Remote Invoke router and CLI caller implementation.</li><li>Restart the sync server and verify only the matching caller protocol version.</li></ol>',29)])])}const m=o(n,[["render",i]]);export{u as __pageData,m as default};
